Случай I. Запрос: Как приготовить борщ. Дай ответ строго в виде md файла Ответ: { "name": "Борщ", "products": [ { "product": { "name": "Говядина (на кости)", "unit": "кг" }, "amount": 0.5, "required": true }, { "product": { "name": "Свекла", "unit": "кг" }, "amount": 0.4, "required": true }, { "product": { "name": "Капуста белокочанная", "unit": "кг" }, "amount": 0.5, "required": true }, { "product": { "name": "Картофель", "unit": "кг" }, "amount": 0.6, "required": true }, { "product": { "name": "Морковь", "unit": "шт" }, "amount": 1, "required": true }, { "product": { "name": "Лук репчатый", "unit": "шт" }, "amount": 1, "required": true }, { "product": { "name": "Томатная паста", "unit": "ст. л." }, "amount": 2, "required": true }, { "product": { "name": "Соль", "unit": "ч. л." }, "amount": 1, "required": true }, { "product": { "name": "Черный молотый перец", "unit": "ч. л." }, "amount": 0.5, "required": true }, { "product": { "name": "Сахар", "unit": "ч. л." }, "amount": 1, "required": true }, { "product": { "name": "Лавровый лист", "unit": "шт" }, "amount": 2, "required": true }, { "product": { "name": "Сметана", "unit": "ст. л." }, "amount": 2, "required": true }, { "product": { "name": "Укроп свежий", "unit": "грамм" }, "amount": 10, "required": true }, { "product": { "name": "Растительное масло", "unit": "ст. л." }, "amount": 2, "required": true }, { "product": { "name": "Вода", "unit": "л" }, "amount": 2.5, "required": true } ], "utensils": [ "Большая кастрюля", "Сковорода", "Нож", "Разделочная доска", "Ложка", "Лопатка", "Тёрка", "Миска" ], "steps": [ { "title": "Подготовка ингредиентов", "instruction": "Свеклу очистить и натереть на крупной тёрке. Морковь очистить и натереть. Лук мелко нарезать. Картофель очистить и нарезать кубиками (2 см). Капусту нашинковать. Говядину промыть, обсушить и нарезать кусками размером 2–3 см.", "duration": 15, "utensils": [ "Нож", "Разделочная доска", "Тёрка", "Миска" ] }, { "title": "Варка бульона", "instruction": "В большую кастрюлю налить 2,5 л воды, добавить говядину, довести до кипения, снять пену, добавить соль, лавровый лист и варить на среднем огне 45 минут.", "duration": 45, "utensils": [ "Большая кастрюля", "Ложка" ] }, { "title": "Обжарка овощей", "instruction": "На сковороде разогреть растительное масло, добавить лук и морковь, обжаривать 5 минут до мягкости. Затем добавить натёртую свёклу, томатную пасту, сахар и немного воды, тушить 10 минут, периодически помешивая.", "duration": 15, "utensils": [ "Сковорода", "Лопатка" ] }, { "title": "Сборка борща", "instruction": "В готовый бульон добавить картофель, варить 10 минут. Затем добавить капусту, варить ещё 5 минут. Влить овощную смесь из сковороды, перемешать, довести до кипения и варить 5 минут. В конце добавить перец по вкусу.", "duration": 20, "utensils": [ "Большая кастрюля", "Ложка" ] }, { "title": "Подача", "instruction": "Разлить борщ по тарелкам, добавить по вкусу сметану и посыпать свежим укропом. Подавать горячим.", "duration": 5, "utensils": [ "Тарелка", "Ложка" ] } ], "advice": [ "Для более яркого цвета свёклу можно предварительно обжарить с небольшим уксусом.", "Борщ лучше дать настояться 15‑20 минут перед подачей – вкус станет глубже.", "Если хотите более насыщенный бульон, готовьте говядину на медленном огне 1,5‑2 часа." ]
} Случай II. Запрос: Какие ингредиенты нужны для омлета. Не включай в ответ поля steps, utensils. Ответ: { "name": "Омлет", "products": [ { "product": { "name": "яйца", "unit": "шт" }, "amount": 3, "required": true }, { "product": { "name": "молоко", "unit": "мл" }, "amount": 30, "required": true }, { "product": { "name": "соль", "unit": "ч.л." }, "amount": 0.5, "required": true }, { "product": { "name": "перец черный молотый", "unit": "ч.л." }, "amount": 0.25, "required": true }, { "product": { "name": "масло сливочное", "unit": "г" }, "amount": 10, "required": true }, { "product": { "name": "зелень (петрушка, укроп)", "unit": "г" }, "amount": 5, "required": false }, { "product": { "name": "сыр твердый", "unit": "г" }, "amount": 30, "required": false } ], "utensils": [], "steps": [], "advice": []
} Случай III. Запрос: Как приготовить пиццу. Добавь в ответ поле "description": "string", в котором дай краткое описание блюда. Ответ: { "name": "Классическая пицца Маргарита", "description": "Классическая итальянская пицца с тонким хрустящим тестом, ароматным томатным соусом и расплавленным моцареллой.", "products": [ { "product": { "name": "Мука (тип 00)", "unit": "г" }, "amount": 500, "required": true }, { "product": { "name": "Вода", "unit": "мл" }, "amount": 300, "required": true }, { "product": { "name": "Сухие дрожжи", "unit": "г" }, "amount": 7, "required": true }, { "product": { "name": "Соль", "unit": "г" }, "amount": 10, "required": true }, { "product": { "name": "Сахар", "unit": "г" }, "amount": 5, "required": true }, { "product": { "name": "Оливковое масло", "unit": "мл" }, "amount": 30, "required": true }, { "product": { "name": "Томатный соус", "unit": "г" }, "amount": 200, "required": true }, { "product": { "name": "Моцарелла", "unit": "г" }, "amount": 200, "required": true }, { "product": { "name": "Свежий базилик", "unit": "лист" }, "amount": 5, "required": false }, { "product": { "name": "Сушеный орегано", "unit": "г" }, "amount": 2, "required": false }, { "product": { "name": "Черный молотый перец", "unit": "г" }, "amount": 1, "required": false } ], "utensils": [ "Миска для замешивания", "Кухонные весы", "Венчик или ложка", "Кухонное полотенце", "Скалка", "Пергаментная бумага", "Пицца‑переложка (пелл)", "Пекарный камень или противень", "Духовка", "Нож", "Разделочная доска" ], "steps": [ { "title": "Подготовка теста", "instruction": "В миске смешайте муку, соль и сахар. В отдельной чашке растворите дрожжи в теплой воде, дайте постоять 5 минут. Влейте дрожжевую смесь и оливковое масло в сухие ингредиенты, замесите тесто. Вымесите 8‑10 минут до гладкой эластичной консистенции. Сформируйте шар, накройте кухонным полотенцем и оставьте в теплом месте на 1,5‑2 часа, пока тесто не увеличится в объеме вдвое.", "duration": 120, "utensils": [ "Миска для замешивания", "Кухонные весы", "Венчик или ложка", "Кухонное полотенце" ] }, { "title": "Приготовление соуса", "instruction": "В отдельной миске смешайте томатный соус, щепотку соли, черный молотый перец и сушеный орегано. По желанию добавьте немного сахара для баланса кислотности. Перемешайте до однородности.", "duration": 10, "utensils": [ "Миска для замешивания", "Ложка" ] }, { "title": "Формирование основы", "instruction": "Разогрейте духовку до 250 °C с пекарным камнем внутри. На слегка присыпанной мукой поверхности раскатайте поднявшееся тесто в круг диаметром 30 см, толщиной около 3 мм. Перенесите раскатанное тесто на пергаментную бумагу, смазанную оливковым маслом. Сверху равномерно распределите томатный соус, посыпьте натертой моцареллой и разложите листики базилика.", "duration": 15, "utensils": [ "Скалка", "Пергаментная бумага", "Нож", "Разделочная доска" ] }, { "title": "Выпекание", "instruction": "С помощью пицца‑переложки перенесите пиццу (вместе с пергаментом) на горячий пекарный камень. Выпекайте 10‑12 минут, пока корочка не станет золотистой, а сыр полностью не расплавится и не начнет слегка подрумяниваться.", "duration": 12, "utensils": [ "Духовка", "Пекарный камень", "Пицца‑переложка (пелл)" ] }, { "title": "Подача", "instruction": "Выньте готовую пиццу из духовки, дайте ей отдохнуть 2‑3 минуты, затем разрежьте на 6‑8 кусочков. Подавайте горячей, при желании украсив дополнительными листиками базилика.", "duration": 5, "utensils": [ "Нож", "Разделочная доска" ] } ], "advice": [ "Для более ароматного теста оставьте его подниматься в холодильнике на ночь.", "Если нет пекарного камня, используйте толстый противень, предварительно разогретый в духовке.", "Не перегружайте пиццу начинкой – это может сделать корочку soggy (мокрой).", "Перед выпеканием слегка смазать края теста оливковым маслом для золотистой корочки." ]
} Общий Вывод по пункту 3 Модель в целом следует заданному формату JSON, но с нюансами. В случае II она отказалась удалять поля, но оставила их пустыми массивами. В случае III она добавила поле по запросу пользователя, которого нет в исходной схеме. Исходя из этого следует продумать, доспустимы ли пустые массивы и дополнительные поля, которых не в оригинальной схеме. При необходимости добавить эти ограничения в системный промпт, например: Список кухонной утварь utensils должен содеражать хотя бы 1 элемент В схеме вывода недопустимы никакие дополнительные поля, кроме указанных В дополнение к этому можно применить SGR (Schema-Guided Reasoning)
